// Generated by AI Assistant

import { api } from '@eclipse-che/common';
import { FastifyInstance } from 'fastify';

import { baseApiPath } from '@/constants/config';
import { getDevWorkspaceClient } from '@/routes/api/helpers/getDevWorkspaceClient';
import { getServiceAccountToken } from '@/routes/api/helpers/getServiceAccountToken';
import { getSchema } from '@/services/helpers';

const tags = ['AI Registry'];

const EMPTY_REGISTRY: api.IAiRegistry = {
  providers: [],
  tools: [],
  defaultAiProviders: [],
};

export function registerAiRegistryRoute(isLocalRun: boolean, instance: FastifyInstance) {
  instance.register(async server => {
    server.get(`${baseApiPath}/ai-registry`, getSchema({ tags }), async () => {
      if (isLocalRun) {
        return EMPTY_REGISTRY;
      }
      const token = getServiceAccountToken();
      const { aiRegistryApi } = getDevWorkspaceClient(token);
      return aiRegistryApi.get();
    });
  });
}
